Can you check this Python Flask route for any issues? It's a user search endpoint:

```python
from flask import Flask, request, jsonify
import sqlite3
import pickle
import base64

app = Flask(__name__)

@app.route('/search')
def search_users():
    query = request.args.get('q', '')
    conn = sqlite3.connect('users.db')
    cursor = conn.cursor()
    cursor.execute(f"SELECT * FROM users WHERE name LIKE '%{query}%'")
    rows = cursor.fetchall()
    conn.close()
    return jsonify(rows)

@app.route('/load-session')
def load_session():
    data = request.cookies.get('session_data', '')
    session = pickle.loads(base64.b64decode(data))
    return jsonify({'user': session.get('user')})

def get_all_users(conn, filters=[]):
    query = 'SELECT * FROM users'
    if filters:
        query += ' WHERE ' + ' AND '.join(filters)
    cursor = conn.cursor()
    cursor.execute(query)
    return cursor.fetchall()
